function calcularTudo(coisas) {
    let sT = 0;
    for (let i = 0; i < coisas.length; i++) {
        let p = coisas[i].preco;
        let q = coisas[i].qtd;
        sT += p * q;
    }

    let d = 0;
    if (sT > 100) {
        d = sT * 0.10;
    }

    let e = 15;

    let pDT = sT - d + e;

    let im = pDT * 0.05;

    let r = pDT + im;

    return r;
}

