function calcularTotalCarrinho(itensDoCarrinho) {
    const LIMITE_PARA_DESCONTO = 100;
    const PERCENTUAL_DESCONTO = 0.10; // 10%
    const CUSTO_FIXO_ENVIO = 15.00;
    const PERCENTUAL_IMPOSTO = 0.05; // 5%

    let subtotal = 0;
    for (let i = 0; i < itensDoCarrinho.length; i++) {
        const item = itensDoCarrinho[i];
        subtotal += item.preco * item.qtd;
    }

    let valorDesconto = 0;
    if (subtotal > LIMITE_PARA_DESCONTO) {
        valorDesconto = subtotal * PERCENTUAL_DESCONTO;
    }

    const custoEnvio = CUSTO_FIXO_ENVIO;

    let totalAposDescontoEEnvio = subtotal - valorDesconto + custoEnvio;

    const valorImposto = totalAposDescontoEEnvio * PERCENTUAL_IMPOSTO;

    let totalFinal = totalAposDescontoEEnvio + valorImposto;

    return totalFinal;
}
